mapper.select:
SELECT r.id, r.date_time as createtime, r.asset_id, r.remark, r.type, r.operator, r.applicant,
       a.maintenance_id as maintenanceId, 
       a.type as assetType,
       a.brand as assetBrand,
       a.asset_no as assetNo
FROM bus_asset_record r
LEFT JOIN bus_asset a ON r.asset_id = a.id


        AND r.type = #{record.type}


        AND a.maintenance_id LIKE '%' || #{record.maintenanceId} || '%'


        AND a.asset_no = #{record.assetNo}


        AND r.asset_id = #{record.assetId}


        AND (r.type LIKE '%入库%' OR r.type = 'IN')


        AND (r.type LIKE '%出库%' OR r.type = 'OUT')


        AND r.date_time >= #{startTime}


        AND r.date_time <= #{endTime}


ORDER BY r.date_time DESC
